package books

import (
	"context"
	"encore.dev/storage/sqldb"
)

type Book struct {
	ID     int    `json:"id"`
	Title  string `json:"title"`
	Author string `json:"author"`
}

type AddBookParams struct {
	Title  string `json:"title"`
	Author string `json:"author"`
}

type ListBooksResponse struct {
	Books []Book `json:"books"`
}

// Define the database
var db = sqldb.New("books", sqldb.DatabaseConfig{
	Migrations: "./migrations",
})

//encore:api public method=POST path=/books
func AddBook(ctx context.Context, params *AddBookParams) (*Book, error) {
	var b Book
	err := db.QueryRow(ctx, `
		INSERT INTO books (title, author)
		VALUES ($1, $2)
		RETURNING id, title, author
	`, params.Title, params.Author).Scan(&b.ID, &b.Title, &b.Author)
	if err != nil {
		return nil, err
	}
	return &b, nil
}

//encore:api public method=GET path=/books
func ListBooks(ctx context.Context) ([]*Book, error) {
	rows, err := db.Query(ctx, `
		SELECT id, title, author FROM books
	`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var books []*Book
	for rows.Next() {
		var b Book
		if err := rows.Scan(&b.ID, &b.Title, &b.Author); err != nil {
			return nil, err
		}
		books = append(books, &b)
	}
	return books, nil
}

